#include <bits/stdc++.h>
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
NP io
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
CI MAXN=2e5+5;
int n,m,a,b,v[MAXN],sum,f[MAXN]; 
vector<int> g[MAXN];
queue<int>q;
int main(void)
{
    n=io::read();
    m=io::read();
    a=io::read();
    b=io::read();
    FOR(i,0,n-1)
    {
        v[i]=io::read();
	}
    FOR(i,1,m)
    {
        int x=io::read(),y=io::read();
        g[x].pb(y);
    }
    if(a==b)
    {
    	puts("0");
    	exit(false);
	}
    cli(f);
	f[a]=0;
	q.push(a);
    while(!q.empty())
    {
    	int u=q.front();
		q.pop();
        FOI(s,g[u]) 
        {
            if(f[s]>f[u]+1)
            {
    			f[s]=f[u]+1;
    			q.push(s);
			}
        }
	}
    if(f[b]==inf)
    {
        puts("No solution");
	}
	else
    {
        io::write(f[b]+v[b]-v[a]);
	}
    return false;
}
